var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-25: <color=#ffd34c>【기록-010】 외부 자료</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS003M0008-25：<color=#ffd34c>【記録-010】 外部資料</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-25: <color=#ffd34c>【Record-010】 External Material</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-25: <color=#ffd34c>【記錄-010】 外部材料</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เปิดทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข AS003M0008-25: <color=#ffd34c>[บันทึก-010] เอกสารประกอบจากภายนอก</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số AS003M0008-25: <color=#ffd34c>[Hồ Sơ-010] Tài Liệu Bên Ngoài</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. AS003M0008-25: <color=#ffd34c>【记录-010】 外部材料</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. AS003M0008-25: <color=#ffd34c>【Aufzeichnung-010】 Externes Material</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. AS003M0008-25\xA0: <color=#ffd34c>【Rapport-010】 Ressource externe</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"【AT-0287Y】 관찰일지Ⅲ","JPN":"【 AT-0287Y 】 観察日誌Ⅲ","ENG":"【AT-0287Y】 Observation Log III","TWN":"【AT-0287Y】觀察日誌III"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y는 실험대상 중 가장 순종적입니다.","JPN":"- AT-0287Yは、実験対象のうち最も従順な個体です。","ENG":"- AT-0287Y is the most submissive amongst the experiment subjects.","TWN":"AT-0287Y是實驗對象中最順從的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"- 시설의 불합리한 규칙에 순응하는 모습과 차별적인 대우에 반발하지 않는 태도를 보아, 유년기에 유사한 경험을 한 것으로 추정됩니다.","JPN":"― 施設の不合理な規則にも順応し、差別的な待遇にも反発を示さない態度から見て、幼年期に類似した経験をしているものと思われます。","ENG":"- It is assumed that the subject already has had similar experiences, adapting to the irrational regulations of the facility and remaining docile against discrimination.","TWN":"從遵守設施不合理的規定，以及不反抗差別對待的態度來看，推測幼年期有同樣的經歷。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"- 일일 평균 체벌 횟수는 입소 후 0.6회를 유지 중입니다.","JPN":"― 1日の平均体罰回数は、入所以来0.6回を維持しています。","ENG":"- The average daily punishment count is being maintained around 0.6.","TWN":"入所後，每日平均體罰次數維持在0.6次。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0195K가 AT-0287Y에게 지속적인 물리적•언어적 폭력을 가하고 있다는 사실을 확인했습니다.","JPN":"- AT-0195KがAT-0287Yに対して持続的に物理的・言語的暴力を加えている事実を確認しました。","ENG":"- It has been confirmed that AT-0195K is constantly exerting physical and verbal abuse against AT-0287Y.","TWN":"已確認AT-0195K對AT-0287Y施加持續的物理性•語言性暴力。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"연구진은 1개체를 소모해서 실험군의 질서를 유지하는 것이 효과적이라고 판단했습니다.","JPN":"― 研究チームは、1個体を消費することで、実験群の秩序を維持することが効果的と判断しました。","ENG":"The researchers have determined that it is best to maintain order by using one of the subjects.","TWN":"研究者認為，消耗一個對象來維持實驗群的秩序是很有效果的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0195K에게 보상으로 <color=#ffd34c>반장</color> 직위를 부여하고 질서 유지를 위임했습니다.","JPN":"- AT-0195Kに報酬として<color=#ffd34c>班長</color>の職位を付与し、秩序維持を委任しました。","ENG":"- AT-0195K was rewarded with the title of <color=#ffd34c>Chief</color>, along with the authority to maintain order.","TWN":"作為給AT-0195K的獎勵，賦予<color=#ffd34c>班長</color>職位，以維持秩序。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"【 AT-0287Y 】 관찰일지Ⅴ","JPN":"【 AT-0287Y 】 観察日誌Ⅴ","ENG":"【AT-0287Y】 Observation Log V","TWN":"【AT-0287Y】觀察日誌V"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0195K가 AT-0287Y에게 가하는 폭력 수위가 연구진의 예상대로 높아지고 있습니다.","JPN":"― AT-0195KがAT-0287Yに加える暴力の度合いが、研究チームの予想通り上昇しています。","ENG":"- The level of violence AT-0195K is exerting upon AT-0287Y has increased as the researchers have predicted.","TWN":"AT-0195K對AT-0287Y的暴力程度，與研究者預想的一樣加深了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"- 기대했던 ███의 발현은 관찰되지 않았습니다. 보다 강한 심리적인 압박이 필요하다고 사료됩니다.","JPN":"― 期待した█████の発現は観察されていません。より強い心理的圧迫が必要と思われます。","ENG":"- There were no expected signs of ███ manifestation. It is assumed to require stronger psychological pressure.","TWN":"未觀測到期許的███表現，看來需增加更強的心理壓迫。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0225X가 Q에게 AT-0287Y의 보호 조치를 요구했습니다. AT-0225X는 AT-0287Y가 의존하는 실험대상입니다.","JPN":"- AT-0225XがQにAT-0287Yの保護措置を求めました。AT-0225XはAT-0287Yが依存している実験対象です。","ENG":"- AT-0225X made a request to Q to protect AT-0287Y. AT-0225X is a subject AT-0287Y relies upon.","TWN":"AT-0225X向Q要求AT-0287Y的保護措施。AT-0225X是AT-0287Y依賴的實驗對象。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"【 AT-0287Y 】 관찰일지Ⅵ","JPN":"【 AT-0287Y 】 観察日誌Ⅵ","ENG":"【AT-0287Y】 Observation Log VI","TWN":"【AT-0287Y】觀察日誌VI"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y가 커리큘럼에 적극적으로 참여하기 시작했습니다. 보상으로 체벌 수위를 1단계 하향 조정하고 추이를 관찰 중입니다.","JPN":"- AT-0287Yがカリキュラムに積極的に参加し始めました。報酬として体罰の度合いを1段階引き下げ、推移を観察しています。","ENG":"- AT-0287Y is actively engaging in the curriculum. Progression is being observed after reducing punishment level by 1 as a reward.","TWN":"AT-0287Y開始積極參與課程。作為獎勵，體罰等級下調1個階段，繼續進行觀察。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"- 직접적인 계기는 AT-0147S가 AT-0287Y에 대한 AT-0195K의 사적 체벌을 막은 사건입니다.","JPN":"- 直接の契機は、AT-0147SがAT-0287Yに対するAT-0195Kの私的体罰を制止した事件です。","ENG":"- The direct influence came from AT-0147S stopping AT-0195K from acting violent against AT-0287Y.","TWN":"直接的契機，是AT-0147S阻止了AT-0195K對AT-0287Y的私下體罰事件。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"AT-0195K와 AT-0147S의 충돌을 목격하고 심경의 변화가 일어난 것으로 추정됩니다.","JPN":"- AT-0195KとAT-0147Sの衝突を目撃し、心境の変化が起きたものと思われます。","ENG":"We assume the subject changed after witnessing the clash between AT-0195K and AT-0147S.","TWN":"推測是目擊到AT-0195K和AT-0147S的衝突，心境發生了變化。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y가 일과 중 AT-0147S를 따라다니는 시간이 늘었습니다.","JPN":"- AT-0287Yが日中、AT-0147Sを追いかける時間が増えています。","ENG":"- AT-0287Y is spending more time following around AT-0147S during the day.","TWN":"AT-0287Y在一天中，跟著AT-0147S的時間增加了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"AT-0287Y는 AT-0147S에게 동경심을 표출하면서 사소한 행동도 남의 눈을 피해 흉내 내고 있습니다.","JPN":"- AT-0287YはAT-0147Sに憧れの感情を示し​つつ、些細な行動までも人目を忍び模倣しています。","ENG":"AT-0287Y has shown admiration towards AT-0147S and is secretly mimicking her behavior.","TWN":"AT-0287Y對AT-0147S表現出憧憬的同時，在他人看不到的地方，模仿AT-0147S的行為。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};